**Services/AppointmentService.cs**:
```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsForDateAsync(DateTime date)
        => await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

    public async Task<List<Appointment>> GetAllAppointmentsAsync()
        => await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .OrderByDescending(a => a.StartTime)
            .ToListAsync();

    public async Task<Appointment?> GetAppointmentAsync(int id)
        => await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Include(a => a.Invoice)
            .FirstOrDefaultAsync(a => a.Id == id);

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment is not null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<DateTime>> GetAvailableSlotsAsync(DateTime date)
    {
        var booked = await db.Appointments
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.StartTime)
            .ToListAsync();

        var slots = new List<DateTime>();
        var start = date.Date.AddHours(8); // Clinic opens at 8 AM
        var end = date.Date.AddHours(17);   // Clinic closes at 5 PM

        while (start < end)
        {
            if (!booked.Any(b => b >= start && b < start.AddMinutes(30)))
            {
                slots.Add(start);
            }
            start = start.AddMinutes(30);
        }

        return slots;
    }
}
