**Services/BillingService.cs**:
```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync()
        => await db.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();

    public async Task<Invoice?> GetInvoiceAsync(int id)
        => await db.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.IssuedDate = DateTime.Now;
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        payment.PaidDate = DateTime.Now;
        db.Payments.Add(payment);

        var invoice = await db.Invoices.Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice is not null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            invoice.Status = totalPaid >= invoice.Amount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        }

        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync()
        => await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Appointment).ThenInclude(a => a.Pet)
            .OrderByDescending(p => p.PaidDate)
            .ToListAsync();
}
