                    <p><strong>Time:</strong> @appointment.StartTime.ToString("HH:mm") - @appointment.EndTime.ToString("HH:mm")</p>
                    <p><strong>Reason:</strong> @appointment.Reason</p>
                    <p><strong>Notes:</strong> @appointment.Notes</p>

                    @if (appointment.Status == AppointmentStatus.Scheduled)
                    {
                        <h5 class="mt-3">Reschedule</h5>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <input type="date" class="form-control" @bind="rescheduleDate" @bind:event="onchange" @bind:after="LoadSlots" />
                            </div>
                            <div class="col-md-6">
                                @if (availableSlots is not null && availableSlots.Count > 0)
                                {
                                    <select class="form-select" @bind="rescheduleSlot">
                                        <option value="">Select time...</option>
                                        @foreach (var slot in availableSlots)
                                        {
                                            <option value="@slot.ToString("o")">@slot.ToString("HH:mm")</option>
                                        }
                                    </select>
                                }
                            </div>
                        </div>
                        <button class="btn btn-warning btn-sm" @onclick="Reschedule" disabled="@string.IsNullOrEmpty(rescheduleSlot)">Reschedule</button>
                        <button class="btn btn-outline-success btn-sm ms-2" @onclick="MarkCompleted">Mark Completed</button>
                        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="Cancel">Cancel Appointment</button>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header">Invoice</div>
                <div class="card-body">
                    @if (appointment.Invoice is null)
                    {
                        @if (appointment.Status == AppointmentStatus.Completed)
                        {
                            <h5>Generate Invoice</h5>
                            <div class="mb-2">
                                <label class="form-label">Amount</label>
                                <input type="number" class="form-control" step="0.01" @bind="invoiceAmount" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Description</label>
                                <input type="text" class="form-control" @bind="invoiceDescription" />
                            </div>
                            <button class="btn btn-primary btn-sm" @onclick="GenerateInvoice">Generate Invoice</button>
                        }
                        else
                        {
                            <p class="text-muted">Complete the appointment to generate an invoice.</p>
                        }
                    }
                    else
                    {
                        <p><strong>Invoice #@appointment.Invoice.Id</strong></p>
                        <p>Amount: $@appointment.Invoice.Amount.ToString("F2")</p>
                        <p>Status: <span class="badge bg-@GetInvoiceColor(appointment.Invoice.Status)">@appointment.Invoice.Status</span></p>
                        <a href="/billing/@appointment.Invoice.Id" class="btn btn-sm btn-outline-info">View Invoice</a>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Appointment? appointment;
    private DateTime rescheduleDate = DateTime.Today;
    private string rescheduleSlot = string.Empty;
    private List<DateTime>? availableSlots;
    private decimal invoiceAmount;
    private string invoiceDescription = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        appointment = await AppointmentService.GetAppointmentAsync(Id);
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(rescheduleDate);
    }

    private async Task Reschedule()
    {
        if (appointment is null || string.IsNullOrEmpty(rescheduleSlot)) return;
        var newStart = DateTime.Parse(rescheduleSlot);
        appointment.StartTime = newStart;
        appointment.EndTime = newStart.AddMinutes(30);
        await AppointmentService.UpdateAppointmentAsync(appointment);
        appointment = await AppointmentService.GetAppointmentAsync(Id);
    }

    private async Task MarkCompleted()
    {
        if (appointment is null) return;
        appointment.Status = AppointmentStatus.Completed;
        await AppointmentService.UpdateAppointmentAsync(appointment);
        appointment = await AppointmentService.GetAppointmentAsync(Id);
    }

    private async Task Cancel()
    {
        await AppointmentService.CancelAppointmentAsync(Id);
        Navigation.NavigateTo("/appointments");
    }

    private async Task GenerateInvoice()
    {
        if (appointment is null) return;
        var invoice = new Invoice
        {
            AppointmentId = appointment.Id,
            Amount = invoiceAmount,
            Description = invoiceDescription,
            Status = InvoiceStatus.Pending
        };
        await BillingService.CreateInvoiceAsync(invoice);
        appointment = await AppointmentService.GetAppointmentAsync(Id);
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };

    private string GetInvoiceColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "secondary"
    };
}
```

