@inject AppointmentService AppointmentService
@inject PatientService PatientService

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row">
    <div class="col-md-6">
        <div class="card mb-3">
            <div class="card-header"><h5>Today's Appointments</h5></div>
            <div class="card-body">
                @if (todayAppointments is null)
                {
                    <p><em>Loading...</em></p>
                }
                else if (todayAppointments.Count == 0)
                {
                    <p class="text-muted">No appointments scheduled for today.</p>
                }
                else
                {
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var apt in todayAppointments)
                            {
                                <tr>
                                    <td>@apt.StartTime.ToString("HH:mm")</td>
                                    <td>@apt.Pet.Name</td>
                                    <td>@apt.Pet.Owner.LastName</td>
                                    <td>@apt.Reason</td>
                                    <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card mb-3">
            <div class="card-header"><h5>Quick Actions</h5></div>
            <div class="card-body">
                <a href="/patients/new" class="btn btn-primary me-2">Register New Patient</a>
                <a href="/appointments/new" class="btn btn-success me-2">New Appointment</a>
                <a href="/billing" class="btn btn-info">View Invoices</a>
            </div>
        </div>
        <div class="card">
            <div class="card-header"><h5>Recent Patients</h5></div>
            <div class="card-body">
                @if (recentPets is null)
                {
                    <p><em>Loading...</em></p>
                }
                else
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var pet in recentPets.Take(5))
                        {
                            <li class="list-group-item d-flex justify-content-between">
                                <span>@pet.Name (@pet.Species) - Owner: @pet.Owner.LastName</span>
                                <a href="/patients/@pet.Id" class="btn btn-sm btn-outline-primary">View</a>
                            </li>
                        }
                    </ul>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private List<Appointment>? todayAppointments;
    private List<Pet>? recentPets;

    protected override async Task OnInitializedAsync()
    {
        todayAppointments = await AppointmentService.GetAppointmentsForDateAsync(DateTime.Today);
        recentPets = await PatientService.GetAllPetsAsync();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        AppointmentStatus.NoShow => "warning",
        _ => "secondary"
    };
}
```

