            <label class="form-label">Date of Birth</label>
            <InputDate class="form-control" @bind-Value="model.DateOfBirth" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Weight (kg)</label>
            <InputNumber class="form-control" @bind-Value="model.Weight" />
        </div>
