                </div>
                <div class="card-body">
                    @if (showAddNote)
                    {
                        <EditForm Model="newNote" OnValidSubmit="AddTreatmentNote" class="mb-3 p-3 border rounded">
                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Diagnosis</label>
                                    <InputText class="form-control" @bind-Value="newNote.Diagnosis" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Treatment</label>
                                    <InputText class="form-control" @bind-Value="newNote.Treatment" />
                                </div>
                            </div>
                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Medication</label>
                                    <InputText class="form-control" @bind-Value="newNote.Medication" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Veterinarian</label>
                                    <InputText class="form-control" @bind-Value="newNote.VeterinarianName" />
                                </div>
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Notes</label>
                                <InputTextArea class="form-control" @bind-Value="newNote.Notes" />
                            </div>
                            <button type="submit" class="btn btn-success btn-sm">Save</button>
                            <button type="button" class="btn btn-secondary btn-sm" @onclick="() => showAddNote = false">Cancel</button>
                        </EditForm>
                    }

                    @if (pet.TreatmentNotes.Count == 0)
                    {
                        <p class="text-muted">No treatment notes yet.</p>
                    }
                    else
                    {
                        @foreach (var note in pet.TreatmentNotes)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <div class="d-flex justify-content-between">
                                    <strong>@note.Date.ToShortDateString()</strong>
                                    <span class="text-muted">Dr. @note.VeterinarianName</span>
                                </div>
                                <p class="mb-1"><strong>Diagnosis:</strong> @note.Diagnosis</p>
                                <p class="mb-1"><strong>Treatment:</strong> @note.Treatment</p>
                                @if (!string.IsNullOrEmpty(note.Medication))
                                {
                                    <p class="mb-1"><strong>Medication:</strong> @note.Medication</p>
                                }
                                @if (!string.IsNullOrEmpty(note.Notes))
                                {
                                    <p class="mb-0 text-muted"><em>@note.Notes</em></p>
                                }
                            </div>
                        }
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private bool showAddNote;
    private TreatmentNote newNote = new();

    protected override async Task OnInitializedAsync()
    {
        pet = await PatientService.GetPetAsync(Id);
    }

    private async Task AddTreatmentNote()
    {
        newNote.PetId = Id;
        newNote.Date = DateTime.Now;
        await PatientService.AddTreatmentNoteAsync(newNote);
        newNote = new();
        showAddNote = false;
        pet = await PatientService.GetPetAsync(Id);
    }
}
