                    <td>
                        <a href="/appointments/@apt.Id" class="btn btn-sm btn-outline-primary">Details</a>
                        @if (apt.Status == AppointmentStatus.Scheduled)
                        {
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt.Id)">Cancel</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment>? appointments;

    protected override async Task OnInitializedAsync()
    {
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await AppointmentService.GetAppointmentsForDateAsync(selectedDate);
    }

    private async Task CancelAppointment(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadAppointments();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        AppointmentStatus.NoShow => "warning",
        _ => "secondary"
    };
}
