```razor
@page "/appointments/new"
@attribute [Authorize]
@inject AppointmentService AppointmentService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>New Appointment</PageTitle>

<h1>Schedule Appointment</h1>

<EditForm Model="model" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />

    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Patient</label>
            <InputSelect class="form-select" @bind-Value="model.PetId">
                <option value="0">Select patient...</option>
                @if (pets is not null)
                {
                    @foreach (var pet in pets)
                    {
                        <option value="@pet.Id">@pet.Name (@pet.Species) - @pet.Owner.LastName</option>
                    }
                }
            </InputSelect>
        </div>
        <div class="col-md-6">
            <label class="form-label">Reason</label>
            <InputText class="form-control" @bind-Value="model.Reason" />
        </div>
    </div>

    <div class="row mb-3">
        <div class="col-md-4">
            <label class="form-label">Date</label>
            <input type="date" class="form-control" @bind="model.Date" @bind:event="onchange" @bind:after="LoadSlots" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Available Time Slot</label>
            @if (availableSlots is null)
            {
                <p class="text-muted">Select a date first</p>
            }
            else if (availableSlots.Count == 0)
            {
                <p class="text-danger">No slots available for this date</p>
            }
            else
            {
                <InputSelect class="form-select" @bind-Value="selectedSlot">
                    <option value="">Select time...</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot.ToString("o")">@slot.ToString("HH:mm")</option>
                    }
                </InputSelect>
            }
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Notes</label>
        <InputTextArea class="form-control" @bind-Value="model.Notes" rows="3" />
    </div>

    <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
        @(isSubmitting ? "Scheduling..." : "Schedule Appointment")
    </button>
    <a href="/appointments" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    private AppointmentModel model = new();
    private List<Pet>? pets;
    private List<DateTime>? availableSlots;
    private string selectedSlot = string.Empty;
    private bool isSubmitting;

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetAllPetsAsync();
        model.Date = DateTime.Today;
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(model.Date);
    }

    private async Task HandleSubmit()
    {
        if (model.PetId == 0 || string.IsNullOrEmpty(selectedSlot)) return;

        isSubmitting = true;
        var startTime = DateTime.Parse(selectedSlot);
        var appointment = new Appointment
        {
            PetId = model.PetId,
            StartTime = startTime,
            EndTime = startTime.AddMinutes(30),
            Reason = model.Reason,
            Notes = model.Notes,
            Status = AppointmentStatus.Scheduled
        };

        await AppointmentService.CreateAppointmentAsync(appointment);
        Navigation.NavigateTo("/appointments");
    }

    private class AppointmentModel
    {
        public int PetId { get; set; }
        public DateTime Date { get; set; } = DateTime.Today;
        public string Reason { get; set; } = string.Empty;
        public string Notes { get; set; } = string.Empty;
    }
}
```

