@page "/"
@attribute [Authorize]
@inject AppointmentService AppointmentService
@inject PatientService PatientService

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row">
    <div class="col-md-6">
        <div class="card mb-3">
            <div class="card-header"><h5>Today's Appointments</h5></div>
            <div class="card-body">
                @if (todayAppointments is null)
                {
                    <p><em>Loading...</em></p>
                }
                else if (todayAppointments.Count == 0)
                {
                    <p class="text-muted">No appointments scheduled for today.</p>
                }
                else
                {
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var apt in todayAppointments)
                            {
                                <tr>
                                    <td>@apt.StartTime.ToString("HH:mm")</td>
                                    <td>@apt.Pet.Name</td>
                                    <td>@apt.Pet.Owner.LastName</td>
                                    <td>@apt.Reason</td>
                                    <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card mb-3">
            <div class="card-header"><h5>Quick Actions</h5></div>
            <div class="card-body">
                <a href="/patients/new" class="btn btn-primary me-2">Register New Patient</a>
                <a href="/appointments/new" class="btn btn-success me-2">New Appointment</a>
                <a href="/billing" class="btn btn-info">View Invoices</a>
            </div>
        </div>
        <div class="card">
            <div class="card-header"><h5>Recent Patients</h5></div>
            <div class="card-body">
                @if (recentPets is null)
                {
                    <p><em>Loading...</em></p>
                }
                else
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var pet in recentPets.Take(5))
                        {
                            <li class="list-group-item d-flex justify-content-between">
                                <span>@pet.Name (@pet.Species) - Owner: @pet.Owner.LastName</span>
                                <a href="/patients/@pet.Id" class="btn btn-sm btn-outline-primary">View</a>
                            </li>
                        }
                    </ul>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private List<Appointment>? todayAppointments;
    private List<Pet>? recentPets;

    protected override async Task OnInitializedAsync()
    {
        todayAppointments = await AppointmentService.GetAppointmentsForDateAsync(DateTime.Today);
        recentPets = await PatientService.GetAllPetsAsync();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        AppointmentStatus.NoShow => "warning",
        _ => "secondary"
    };
}

@page "/patients"
@attribute [Authorize]
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Patients</PageTitle>

<h1>Patients</h1>

<div class="mb-3">
    <a href="/patients/new" class="btn btn-primary">Register New Patient</a>
</div>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search by pet name or owner..." @bind="searchTerm" @bind:event="oninput" />
</div>

@if (pets is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr><th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var pet in FilteredPets)
            {
                <tr>
                    <td>@pet.Name</td>
                    <td>@pet.Species</td>
                    <td>@pet.Breed</td>
                    <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                    <td>
                        <a href="/patients/@pet.Id" class="btn btn-sm btn-outline-primary">View</a>
                        <a href="/patients/@pet.Id/edit" class="btn btn-sm btn-outline-secondary">Edit</a>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Pet>? pets;
    private string searchTerm = string.Empty;

    private IEnumerable<Pet> FilteredPets => pets?.Where(p =>
        string.IsNullOrEmpty(searchTerm) ||
        p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
        p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
        p.Owner.FirstName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
    ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetAllPetsAsync();
    }
}

@page "/patients/new"
@attribute [Authorize]
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Register New Patient</PageTitle>

<h1>Register New Patient</h1>

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="NewPatient">
    <DataAnnotationsValidator />
    <ValidationSummary />

    <h4>Owner Information</h4>
    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">First Name</label>
            <InputText class="form-control" @bind-Value="model.OwnerFirstName" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Last Name</label>
            <InputText class="form-control" @bind-Value="model.OwnerLastName" />
        </div>
    </div>
    <div class="row mb-3">
        <div class="col-md-4">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="model.OwnerPhone" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="model.OwnerEmail" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Address</label>
            <InputText class="form-control" @bind-Value="model.OwnerAddress" />
        </div>
    </div>

    <h4>Pet Information</h4>
    <div class="row mb-3">
        <div class="col-md-4">
            <label class="form-label">Pet Name</label>
            <InputText class="form-control" @bind-Value="model.PetName" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Species</label>
            <InputSelect class="form-select" @bind-Value="model.Species">
                <option value="">Select...</option>
                <option value="Dog">Dog</option>
                <option value="Cat">Cat</option>
                <option value="Bird">Bird</option>
                <option value="Rabbit">Rabbit</option>
                <option value="Reptile">Reptile</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>
        <div class="col-md-4">
            <label class="form-label">Breed</label>
            <InputText class="form-control" @bind-Value="model.Breed" />
        </div>
    </div>
    <div class="row mb-3">
        <div class="col-md-4">
            <label class="form-label">Date of Birth</label>
            <InputDate class="form-control" @bind-Value="model.DateOfBirth" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Weight (kg)</label>
            <InputNumber class="form-control" @bind-Value="model.Weight" />
        </div>
    </div>

    <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
        @(isSubmitting ? "Saving..." : "Register Patient")
    </button>
    <a href="/patients" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    private PatientModel model = new();
    private bool isSubmitting;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        var owner = new Owner
        {
            FirstName = model.OwnerFirstName,
            LastName = model.OwnerLastName,
            Phone = model.OwnerPhone,
            Email = model.OwnerEmail,
            Address = model.OwnerAddress
        };
        owner = await PatientService.CreateOwnerAsync(owner);

        var pet = new Pet
        {
            Name = model.PetName,
            Species = model.Species,
            Breed = model.Breed,
            DateOfBirth = model.DateOfBirth,
            Weight = model.Weight,
            OwnerId = owner.Id
        };
        await PatientService.CreatePetAsync(pet);

        Navigation.NavigateTo("/patients");
    }

    private class PatientModel
    {
        public string OwnerFirstName { get; set; } = string.Empty;
        public string OwnerLastName { get; set; } = string.Empty;
        public string OwnerPhone { get; set; } = string.Empty;
        public string OwnerEmail { get; set; } = string.Empty;
        public string OwnerAddress { get; set; } = string.Empty;
        public string PetName { get; set; } = string.Empty;
        public string Species { get; set; } = string.Empty;
        public string Breed { get; set; } = string.Empty;
        public DateTime DateOfBirth { get; set; } = DateTime.Today;
        public decimal Weight { get; set; }
    }
}

