@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private decimal paymentAmount;
    private string paymentMethod = "Cash";
    private string paymentReference = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        invoice = await BillingService.GetInvoiceAsync(Id);
        if (invoice is not null)
        {
            paymentAmount = invoice.Amount - invoice.Payments.Sum(p => p.Amount);
        }
    }

    private async Task ProcessPayment()
    {
        if (invoice is null || paymentAmount <= 0) return;

        var payment = new Payment
        {
            InvoiceId = invoice.Id,
            Amount = paymentAmount,
            PaymentMethod = paymentMethod,
            Reference = paymentReference
        };

        await BillingService.ProcessPaymentAsync(payment);
        invoice = await BillingService.GetInvoiceAsync(Id);
        paymentAmount = invoice is not null ? invoice.Amount - invoice.Payments.Sum(p => p.Amount) : 0;
        paymentReference = string.Empty;
    }

    private string GetInvoiceColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

