@page "/appointments/{Id:int}"
@attribute [Authorize]
@inject AppointmentService AppointmentService
@inject BillingService BillingService
@inject NavigationManager Navigation

<PageTitle>Appointment Details</PageTitle>

@if (appointment is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>Appointment - @appointment.Pet.Name</h1>
    <p class="text-muted">@appointment.StartTime.ToString("f") | Status: <span class="badge bg-@GetStatusColor(appointment.Status)">@appointment.Status</span></p>

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header">Appointment Info</div>
                <div class="card-body">
                    <p><strong>Pet:</strong> @appointment.Pet.Name (@appointment.Pet.Species)</p>
                    <p><strong>Owner:</strong> @appointment.Pet.Owner.FirstName @appointment.Pet.Owner.LastName</p>
                    <p><strong>Time:</strong> @appointment.StartTime.ToString("HH:mm") - @appointment.EndTime.ToString("HH:mm")</p>
                    <p><strong>Reason:</strong> @appointment.Reason</p>
                    <p><strong>Notes:</strong> @appointment.Notes</p>

                    @if (appointment.Status == AppointmentStatus.Scheduled)
                    {
                        <h5 class="mt-3">Reschedule</h5>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <input type="date" class="form-control" @bind="rescheduleDate" @bind:event="onchange" @bind:after="LoadSlots" />
                            </div>
                            <div class="col-md-6">
                                @if (availableSlots is not null && availableSlots.Count > 0)
                                {
                                    <select class="form-select" @bind="rescheduleSlot">
                                        <option value="">Select time...</option>
                                        @foreach (var slot in availableSlots)
                                        {
                                            <option value="@slot.ToString("o")">@slot.ToString("HH:mm")</option>
                                        }
                                    </select>
                                }
                            </div>
                        </div>
                        <button class="btn btn-warning btn-sm" @onclick="Reschedule" disabled="@string.IsNullOrEmpty(rescheduleSlot)">Reschedule</button>
                        <button class="btn btn-outline-success btn-sm ms-2" @onclick="MarkCompleted">Mark Completed</button>
                        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="Cancel">Cancel Appointment</button>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header">Invoice</div>
                <div class="card-body">
                    @if (appointment.Invoice is null)
                    {
                        @if (appointment.Status == AppointmentStatus.Completed)
                        {
                            <h5>Generate Invoice</h5>
                            <div class="mb-2">
                                <label class="form-label">Amount</label>
                                <input type="number" class="form-control" step="0.01" @bind="invoiceAmount" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Description</label>
                                <input type="text" class="form-control" @bind="invoiceDescription" />
                            </div>
                            <button class="btn btn-primary btn-sm" @onclick="GenerateInvoice">Generate Invoice</button>
                        }
                        else
                        {
                            <p class="text-muted">Complete the appointment to generate an invoice.</p>
                        }
                    }
                    else
                    {
                        <p><strong>Invoice #@appointment.Invoice.Id</strong></p>
                        <p>Amount: $@appointment.Invoice.Amount.ToString("F2")</p>
                        <p>Status: <span class="badge bg-@GetInvoiceColor(appointment.Invoice.Status)">@appointment.Invoice.Status</span></p>
                        <a href="/billing/@appointment.Invoice.Id" class="btn btn-sm btn-outline-info">View Invoice</a>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Appointment? appointment;
    private DateTime rescheduleDate = DateTime.Today;
    private string rescheduleSlot = string.Empty;
    private List<DateTime>? availableSlots;
    private decimal invoiceAmount;
    private string invoiceDescription = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        appointment = await AppointmentService.GetAppointmentAsync(Id);
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(rescheduleDate);
    }

    private async Task Reschedule()
    {
        if (appointment is null || string.IsNullOrEmpty(rescheduleSlot)) return;
        var newStart = DateTime.Parse(rescheduleSlot);
        appointment.StartTime = newStart;
        appointment.EndTime = newStart.AddMinutes(30);
        await AppointmentService.UpdateAppointmentAsync(appointment);
        appointment = await AppointmentService.GetAppointmentAsync(Id);
    }

    private async Task MarkCompleted()
    {
        if (appointment is null) return;
        appointment.Status = AppointmentStatus.Completed;
        await AppointmentService.UpdateAppointmentAsync(appointment);
        appointment = await AppointmentService.GetAppointmentAsync(Id);
    }

    private async Task Cancel()
    {
        await AppointmentService.CancelAppointmentAsync(Id);
        Navigation.NavigateTo("/appointments");
    }

    private async Task GenerateInvoice()
    {
        if (appointment is null) return;
        var invoice = new Invoice
        {
            AppointmentId = appointment.Id,
            Amount = invoiceAmount,
            Description = invoiceDescription,
            Status = InvoiceStatus.Pending
        };
        await BillingService.CreateInvoiceAsync(invoice);
        appointment = await AppointmentService.GetAppointmentAsync(Id);
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };

    private string GetInvoiceColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

@page "/billing"
@attribute [Authorize]
@inject BillingService BillingService

<PageTitle>Billing</PageTitle>

<h1>Billing & Invoices</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    @if (invoices is null)
    {
        <p><em>Loading...</em></p>
    }
    else if (invoices.Count == 0)
    {
        <div class="alert alert-info">No invoices found.</div>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr><th>#</th><th>Date</th><th>Patient</th><th>Owner</th><th>Amount</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var inv in invoices)
                {
                    <tr>
                        <td>@inv.Id</td>
                        <td>@inv.IssuedDate.ToShortDateString()</td>
                        <td>@inv.Appointment.Pet.Name</td>
                        <td>@inv.Appointment.Pet.Owner.LastName</td>
                        <td>$@inv.Amount.ToString("F2")</td>
                        <td><span class="badge bg-@GetInvoiceColor(inv.Status)">@inv.Status</span></td>
                        <td><a href="/billing/@inv.Id" class="btn btn-sm btn-outline-primary">View</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
}
else
{
    @if (payments is null)
    {
        <p><em>Loading...</em></p>
    }
    else if (payments.Count == 0)
    {
        <div class="alert alert-info">No payments recorded.</div>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr><th>Date</th><th>Invoice #</th><th>Patient</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
            </thead>
            <tbody>
                @foreach (var pay in payments)
                {
                    <tr>
                        <td>@pay.PaidDate.ToShortDateString()</td>
                        <td>@pay.InvoiceId</td>
                        <td>@pay.Invoice.Appointment.Pet.Name</td>
                        <td>$@pay.Amount.ToString("F2")</td>
                        <td>@pay.PaymentMethod</td>
                        <td>@pay.Reference</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    private string activeTab = "invoices";
    private List<Invoice>? invoices;
    private List<Payment>? payments;

    protected override async Task OnInitializedAsync()
    {
        invoices = await BillingService.GetInvoicesAsync();
        payments = await BillingService.GetPaymentHistoryAsync();
    }

    private string GetInvoiceColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

@page "/billing/{Id:int}"
@attribute [Authorize]
@inject BillingService BillingService

<PageTitle>Invoice Details</PageTitle>

@if (invoice is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>Invoice #@invoice.Id</h1>

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header">Invoice Details</div>
                <div class="card-body">
                    <p><strong>Date:</strong> @invoice.IssuedDate.ToShortDateString()</p>
                    <p><strong>Patient:</strong> @invoice.Appointment.Pet.Name</p>
                    <p><strong>Owner:</strong> @invoice.Appointment.Pet.Owner.FirstName @invoice.Appointment.Pet.Owner.LastName</p>
                    <p><strong>Description:</strong> @invoice.Description</p>
                    <p><strong>Amount:</strong> $@invoice.Amount.ToString("F2")</p>
                    <p><strong>Status:</strong> <span class="badge bg-@GetInvoiceColor(invoice.Status)">@invoice.Status</span></p>
                    <p><strong>Paid:</strong> $@invoice.Payments.Sum(p => p.Amount).ToString("F2")</p>
                    <p><strong>Balance:</strong> $@((invoice.Amount - invoice.Payments.Sum(p => p.Amount)).ToString("F2"))</p>
                </div>
            </div>
        </div>
        <div class="col-md-6">
            @if (invoice.Status != InvoiceStatus.Paid && invoice.Status != InvoiceStatus.Cancelled)
            {
                <div class="card mb-3">
                    <div class="card-header">Process Payment</div>
                    <div class="card-body">
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <input type="number" class="form-control" step="0.01" @bind="paymentAmount" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Payment Method</label>
                            <select class="form-select" @bind="paymentMethod">
                                <option value="Cash">Cash</option>
                                <option value="Credit Card">Credit Card</option>
                                <option value="Debit Card">Debit Card</option>
                                <option value="Check">Check</option>
                            </select>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reference</label>
                            <input type="text" class="form-control" @bind="paymentReference" placeholder="Transaction ID or check number" />
                        </div>
                        <button class="btn btn-success" @onclick="ProcessPayment">Process Payment</button>
                    </div>
                </div>
            }

            <div class="card">
                <div class="card-header">Payment History</div>
                <div class="card-body">
                    @if (invoice.Payments.Count == 0)
                    {
                        <p class="text-muted">No payments recorded.</p>
                    }
                    else
                    {
                        <table class="table table-sm">
                            <thead>
                                <tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
                            </thead>
                            <tbody>
                                @foreach (var pay in invoice.Payments)
                                {
                                    <tr>
                                        <td>@pay.PaidDate.ToShortDateString()</td>
                                        <td>$@pay.Amount.ToString("F2")</td>
                                        <td>@pay.PaymentMethod</td>
                                        <td>@pay.Reference</td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private decimal paymentAmount;
    private string paymentMethod = "Cash";
    private string paymentReference = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        invoice = await BillingService.GetInvoiceAsync(Id);
        if (invoice is not null)
        {
            paymentAmount = invoice.Amount - invoice.Payments.Sum(p => p.Amount);
        }
    }

    private async Task ProcessPayment()
    {
        if (invoice is null || paymentAmount <= 0) return;

        var payment = new Payment
        {
            InvoiceId = invoice.Id,
            Amount = paymentAmount,
            PaymentMethod = paymentMethod,
            Reference = paymentReference
        };

        await BillingService.ProcessPaymentAsync(payment);
        invoice = await BillingService.GetInvoiceAsync(Id);
        paymentAmount = invoice is not null ? invoice.Amount - invoice.Payments.Sum(p => p.Amount) : 0;
        paymentReference = string.Empty;
    }

    private string GetInvoiceColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

