    public async Task<Owner> CreateOwnerAsync(Owner owner)
    {
        db.Owners.Add(owner);
        await db.SaveChangesAsync();
        return owner;
    }

    public async Task UpdateOwnerAsync(Owner owner)
    {
        db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    public async Task<Pet?> GetPetAsync(int id)
        => await db.Pets.Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task<List<Pet>> GetAllPetsAsync()
        => await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();

    public async Task<Pet> CreatePetAsync(Pet pet)
    {
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        return pet;
    }

    public async Task UpdatePetAsync(Pet pet)
    {
        db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task<TreatmentNote> AddTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
        return note;
    }
}
```

**Services/AppointmentService.cs**:
```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsForDateAsync(DateTime date)
        => await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

    public async Task<List<Appointment>> GetAllAppointmentsAsync()
        => await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .OrderByDescending(a => a.StartTime)
            .ToListAsync();

    public async Task<Appointment?> GetAppointmentAsync(int id)
        => await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Include(a => a.Invoice)
            .FirstOrDefaultAsync(a => a.Id == id);

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment is not null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<DateTime>> GetAvailableSlotsAsync(DateTime date)
    {
        var booked = await db.Appointments
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.StartTime)
            .ToListAsync();

        var slots = new List<DateTime>();
        var start = date.Date.AddHours(8); // Clinic opens at 8 AM
        var end = date.Date.AddHours(17);   // Clinic closes at 5 PM

        while (start < end)
        {
            if (!booked.Any(b => b >= start && b < start.AddMinutes(30)))
            {
                slots.Add(start);
            }
            start = start.AddMinutes(30);
        }

        return slots;
    }
}
```

**Services/BillingService.cs**:
```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync()
        => await db.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();

    public async Task<Invoice?> GetInvoiceAsync(int id)
        => await db.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.IssuedDate = DateTime.Now;
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        payment.PaidDate = DateTime.Now;
        db.Payments.Add(payment);

        var invoice = await db.Invoices.Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice is not null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            invoice.Status = totalPaid >= invoice.Amount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        }

        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync()
        => await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Appointment).ThenInclude(a => a.Pet)
            .OrderByDescending(p => p.PaidDate)
            .ToListAsync();
}
```

